(function () {
  const editors = new Map();

  const createEditor = (target) => {
    const editor = {
      id: target.id || '',
      targetElm: target,
      getContent() {
        return target.value || '';
      },
      setContent(content) {
        target.value = typeof content === 'string' ? content : '';
      },
      insertContent(content) {
        target.value = `${target.value || ''}${typeof content === 'string' ? content : ''}`;
      },
      remove() {
        editors.delete(target);
      }
    };

    editors.set(target, editor);
    return editor;
  };

  const getTargets = (selector) => {
    if (!selector || typeof selector !== 'string') {
      return [];
    }

    return Array.from(document.querySelectorAll(selector)).filter((node) => node && node.tagName === 'TEXTAREA');
  };

  const api = {
    init(config) {
      const options = config && typeof config === 'object' ? config : {};
      const targets = getTargets(options.selector);
      const initialized = targets.map((target) => {
        const editor = createEditor(target);
        if (typeof options.setup === 'function') {
          options.setup({
            ...editor,
            ui: {
              registry: {
                addButton() {
                  return undefined;
                }
              }
            },
            windowManager: {
              openUrl() {
                return undefined;
              }
            }
          });
        }

        return editor;
      });

      return Promise.resolve(initialized);
    },
    triggerSave() {
      return undefined;
    },
    get(id) {
      if (typeof id !== 'string' || !id) {
        return null;
      }

      for (const [target, editor] of editors.entries()) {
        if (target.id === id) {
          return editor;
        }
      }

      return null;
    }
  };

  if (!window.tinymce) {
    window.tinymce = api;
  }
})();
